import{_ as l,o as i,c as e,O as t}from"./chunks/framework.c4f51971.js";const m=JSON.parse('{"title":"产品概览","description":"","frontmatter":{},"headers":[],"relativePath":"product/index.md","filePath":"product/index.md","lastUpdated":1775618461000}'),r={name:"product/index.md"};function o(d,a,h,n,c,s){return i(),e("div",null,a[0]||(a[0]=[t('<h1 id="产品概览" tabindex="-1">产品概览 <a class="header-anchor" href="#产品概览" aria-label="Permalink to &quot;产品概览&quot;">​</a></h1><p>SmartFlow 当前最准确的定义是：</p><p><strong>一个让 AI 在规则内裁决真实脚本执行、同时服务企业交付与个人入口、并逐步走向产品化和生态化的可信 AI 执行平台。</strong></p><h2 id="平台当前不是在做什么" tabindex="-1">平台当前不是在做什么 <a class="header-anchor" href="#平台当前不是在做什么" aria-label="Permalink to &quot;平台当前不是在做什么&quot;">​</a></h2><ul><li>不是自由聊天系统</li><li>不是把企业后台简单裁剪成免费版</li><li>不是只做演示脚本的小工具集合</li></ul><h2 id="平台当前在解决什么" tabindex="-1">平台当前在解决什么 <a class="header-anchor" href="#平台当前在解决什么" aria-label="Permalink to &quot;平台当前在解决什么&quot;">​</a></h2><h3 id="_1-企业交付问题" tabindex="-1">1. 企业交付问题 <a class="header-anchor" href="#_1-企业交付问题" aria-label="Permalink to &quot;1. 企业交付问题&quot;">​</a></h3><ul><li>一个客户一个租户</li><li>一套后端能力中心支撑多个交付前端</li><li>平台超管可以统一治理客户、租户、模板、日志和审计</li></ul><h3 id="_2-ai-执行可信问题" tabindex="-1">2. AI 执行可信问题 <a class="header-anchor" href="#_2-ai-执行可信问题" aria-label="Permalink to &quot;2. AI 执行可信问题&quot;">​</a></h3><ul><li>AI 不是直接自由执行脚本</li><li>AI 先给出计划，再等待确认</li><li>所有关键执行都要留痕、可审计、可回放</li></ul><h3 id="_3-产品入口问题" tabindex="-1">3. 产品入口问题 <a class="header-anchor" href="#_3-产品入口问题" aria-label="Permalink to &quot;3. 产品入口问题&quot;">​</a></h3><ul><li>企业交付承接真实收入</li><li>个人免费版承接增长入口和体验入口</li><li>CLI 承接本地脚本接入与未来本地 Agent</li></ul><h2 id="当前核心口径" tabindex="-1">当前核心口径 <a class="header-anchor" href="#当前核心口径" aria-label="Permalink to &quot;当前核心口径&quot;">​</a></h2><ol><li><code>public</code> 是平台治理域，不是普通租户。</li><li>免费版是“我的技能库”入口，不是企业后台裁剪版。</li><li>平台模板、租户脚本代理、平台自有脚本三条线必须分开。</li><li>单项目先改，最后再同步到聚合壳层。</li></ol><h2 id="当前适合谁" tabindex="-1">当前适合谁 <a class="header-anchor" href="#当前适合谁" aria-label="Permalink to &quot;当前适合谁&quot;">​</a></h2><ul><li>需要把已有 Python / 自动化脚本接成 AI 可调度能力的团队</li><li>需要一套可继续扩租户、扩模板、扩技能的交付底座</li><li>需要同时运营企业项目和个人免费入口的独立开发者 / 小团队</li></ul><h2 id="继续阅读" tabindex="-1">继续阅读 <a class="header-anchor" href="#继续阅读" aria-label="Permalink to &quot;继续阅读&quot;">​</a></h2><ul><li><a href="/smart-flow-ai-skill-platform-doc/product/capabilities.html">核心能力</a></li><li><a href="/smart-flow-ai-skill-platform-doc/product/architecture.html">架构说明</a></li><li><a href="/smart-flow-ai-skill-platform-doc/product/editions.html">版本路线</a></li></ul>',18)]))}const p=l(r,[["render",o]]);export{m as __pageData,p as default};
